<?php
namespace App\Domain\Equipment;use App\Domain\Inventory\ItemClassification;use App\Domain\WorldCatalog\ItemType;use App\Models\Item;use InvalidArgumentException;
final class EquippableItemValidator{private $classification;private $stats;private $hands;public function __construct(ItemClassification $classification,ItemStatBonusValidator $stats,HandItemConfigurationValidator $hands){$this->classification=$classification;$this->stats=$stats;$this->hands=$hands;}public function equipmentType(Item $item){$this->stats->bonuses($item);if($item->equipment_type===null){if($item->item_type===ItemType::EQUIPMENT)throw new InvalidArgumentException('Equipment Item requires equipment_type.');$this->hands->classify($item);return null;}EquipmentType::assertValid($item->equipment_type);if($item->item_type!==ItemType::EQUIPMENT||$this->classification->classify($item)!==ItemClassification::UNIQUE)throw new InvalidArgumentException('Invalid equippable Item classification.');$this->hands->classify($item);return$item->equipment_type;}public function bonuses(Item $item){$this->equipmentType($item);return$this->stats->bonuses($item);}public function assertCompatible(Item $item,$slot){CharacterEquipmentSlot::assertValid($slot);$type=$this->equipmentType($item);if($type===null||CharacterEquipmentSlot::equipmentType($slot)!==$type)throw new InvalidArgumentException('Item is not compatible with the equipment slot.');if($type===EquipmentType::WEAPON){$kind=$this->hands->classify($item);if($kind===HandItemConfigurationValidator::LEGACY_MAIN_HAND_ONLY&&$slot!==CharacterEquipmentSlot::MAIN_HAND)throw new InvalidArgumentException('El objeto heredado solo puede equiparse en la mano principal.');if($kind===HandRequirement::TWO_HAND&&$slot!==CharacterEquipmentSlot::MAIN_HAND)throw new InvalidArgumentException('El arma de dos manos solo puede equiparse en la mano principal.');if($kind===HandRequirement::OFF_HAND_ONLY&&$slot!==CharacterEquipmentSlot::OFF_HAND)throw new InvalidArgumentException('El objeto solo puede equiparse en la mano secundaria.');}return$type;}}
